import{k as e,p as t,u as n}from"./chunks/runtime-core.esm-bundler.PK8HO-US.js";import{t as r}from"./chunks/plugin-vue_export-helper.DrfHhw6c.js";import{n as i,t as a}from"./chunks/template-generator-advanced.CleIDHrl.js";import{n as o,t as s}from"./chunks/gradle-prompt.DgUqZl-T.js";const c=JSON.parse(`{"title":"建立專案","description":"如何一步一步使用 Fabric 範本模組產生器建立新模組專案的指南。","frontmatter":{"title":"建立專案","description":"如何一步一步使用 Fabric 範本模組產生器建立新模組專案的指南。","authors":["Cactooz","IMB11","radstevee"],"files":[]},"headers":[],"relativePath":"zh_tw/1.21.8/develop/getting-started/creating-a-project.md","filePath":"versions/1.21.8/translated/zh_tw/develop/getting-started/creating-a-project.md","lastUpdated":1760721669000}`);var l={name:`zh_tw/1.21.8/develop/getting-started/creating-a-project.md`};function u(r,i,a,o,s,c){return e(),n(`div`,null,[...i[0]||=[t(`<h1 id="h1" tabindex="-1">建立專案 <a class="header-anchor" href="#h1" aria-label="Permalink to “建立專案”">​</a></h1><p>Fabric 提供了一種使用 Fabric 範本模組產生器輕鬆建立新模組專案的方法——如果你願意，你可以使用範例模組倉儲手動建立新專案，你應該參閱<a href="#manual-project-creation">手動建立專案</a>章節。</p><h2 id="generating-a-project" tabindex="-1">生成專案 <a class="header-anchor" href="#generating-a-project" aria-label="Permalink to “生成專案”">​</a></h2><p>你可以使用 <a href="https://fabricmc.net/develop/template/" target="_blank" rel="noreferrer">Fabric 範本模組產生器</a> 生成你的新模組專案 —— 有一些必填的項目，例如模組名稱、套件名稱，以及你想基於其開發的 Minecraft 版本。</p><p>套件名稱應是小寫字母，由點區隔；套件名稱須具有獨特性，避免和其他開發者的套件衝突。 其格式通常反向的是網域名，例如 <code>com.example.mod-id</code>。</p><p><img src="/assets/develop/getting-started/template-generator.png" alt="生成器的預覽圖" loading="lazy"></p><p>如果你想要使用 Kotlin 進行開發，想使用Mojang官方映射而非Yarn映射，或是想增加資料生成器，可以在 <code>Advanced Options</code> 中勾選對應的選項。</p><p><img src="/assets/develop/getting-started/template-generator-advanced.png" alt="Advanced options section" loading="lazy"></p><p>必填項目輸入完後，點擊 <code>Generate</code> 按鈕，產生器會以 zip 檔的形式產生新專案供你使用。</p><p>你需要把這個 zip 檔解壓縮到你想要的位置，然後從 IntelliJ IDEA 開啟解壓縮後的資料夾：</p><p><img src="/assets/develop/getting-started/open-project.png" alt="開啟專案提示" loading="lazy"></p><h2 id="importing-the-project" tabindex="-1">導入專案 <a class="header-anchor" href="#importing-the-project" aria-label="Permalink to “導入專案”">​</a></h2><p>在 IntelliJ IDEA 開啟專案後， IDE 會自動載入專案的 Gradle 配置並執行必要的初始化任務。</p><p>如果你收到關於 Gradle 建構腳本的通知，你應該點擊 <code>Import Gradle Project</code> 按鈕：</p><p><img src="/assets/develop/getting-started/gradle-prompt.png" alt="Gradle 提示" loading="lazy"></p><p>專案導入完成後，你就可以在專案資源管理器中看到專案的檔案，並能開始開發你的模組了。</p><h2 id="manual-project-creation" tabindex="-1">手動建立專案 <a class="header-anchor" href="#manual-project-creation" aria-label="Permalink to “手動建立專案”">​</a></h2><div class="warning custom-block"><p class="custom-block-title custom-block-title-default">WARNING</p><p>你會需要安裝 <a href="https://git-scm.com/" target="_blank" rel="noreferrer">Git</a> 來複製範例模組倉儲。</p></div><p>如果你無法使用 Fabric 範本模組產生器，你可以按照以下步驟手動建立新專案。</p><p>首先，使用 Git 複製範例模組倉儲：</p><div class="language-sh line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">sh</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">git</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> clone</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> https://github.com/FabricMC/fabric-example-mod/</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> my-mod-project</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>這會把倉儲複製到名為 <code>my-mod-porject</code> 的新資料夾中。</p><p>你應該從複製的存儲庫中刪除 <code>.git</code> 資料夾，然後在 IntelliJ IDEA 中打開專案。 如果 <code>.git</code> 資料夾沒有顯示，你需要在檔案管理器中開啟 <code>顯示隱藏的項目</code> 。</p><p>在 IntelliJ IDEA 中開啟專案後，它應該會自動載入專案的 Gradle 配置並執行必要的初始化任務。</p><p>再次強調，如果你收到關於 Gradle 建構腳本的通知，你應該點擊 <code>Import Gradle Project</code> 按鈕。</p><h3 id="modifying-the-template" tabindex="-1">修改模板 <a class="header-anchor" href="#modifying-the-template" aria-label="Permalink to “修改模板”">​</a></h3><p>專案導入後，你應該修改專案的細節，以符合你的模組：</p><ul><li>修改專案中的 <code>gradle.properties</code> 檔案，將 <code>maven_group</code> 和 <code>archive_base_name</code> 屬性改成為你的模組的資訊。</li><li>修改 <code>fabric.mod.json</code> 文件，將 <code>id</code>、<code>name</code> 和 <code>description</code> 屬性改為與你的模組的資訊。</li><li>記得更新Minecraft的版本、映射、Loader和Loom的版本，你可以透過 <a href="https://fabricmc.net/develop/" target="_blank" rel="noreferrer">https://fabricmc.net/develop/</a> 查詢相關資訊，以確保它們符合你期望的目標版本。</li></ul><p>你也可以修改套件名稱和模組的主類別以符合你的模組。</p>`,29)]])}var d=r(l,[[`render`,u]]);export{c as __pageData,d as default};